from dataclasses import dataclass, field
from datetime import date
from enum import Enum
from typing import Optional

class LicenseType(Enum):
    PER_SEAT_SAAS  = "per_seat_saas"
    PAY_PER_USE    = "pay_per_use"
    ENTERPRISE_FLAT= "enterprise_flat"   # unlimited seats, fixed annual fee
    RESERVED_CAPACITY = "reserved_capacity"  # provisioned throughput

class UtilizationStatus(Enum):
    HEALTHY        = "healthy"       # 70–95% utilization
    NEAR_LIMIT     = "near_limit"    # > 95% — may need more seats
    OVER_LICENSED  = "over_licensed" # < 50% — too many seats
    MONITOR        = "monitor"       # 50–70% — watch closely
    UNUSED         = "unused"        # < 10% — candidate for cancellation

@dataclass
class LicenseRecord:
    tool_id: str
    vendor: str
    product_name: str
    license_type: LicenseType
    seat_count: Optional[int]          # None for pay-per-use
    monthly_spend_cap_usd: Optional[float]  # for pay-per-use
    annual_cost_usd: float
    renewal_date: date
    owner_team: str                    # team responsible for the license
    cost_centre: str
    tags: dict[str, str] = field(default_factory=dict)  # e.g. {"purpose": "ide-assistant"}
    notes: str = ""

@dataclass
class UtilizationSnapshot:
    tool_id: str
    period: str                   # YYYY-MM
    active_users: int             # users with at least one session in the period
    total_assigned_seats: int
    api_spend_usd: Optional[float]  # for pay-per-use tools
    avg_sessions_per_user: float

    @property
    def seat_utilization(self) -> Optional[float]:
        if self.total_assigned_seats == 0:
            return None
        return self.active_users / self.total_assigned_seats

    @property
    def status(self) -> UtilizationStatus:
        u = self.seat_utilization
        if u is None:
            return UtilizationStatus.MONITOR
        if u < 0.10:
            return UtilizationStatus.UNUSED
        if u < 0.50:
            return UtilizationStatus.OVER_LICENSED
        if u < 0.70:
            return UtilizationStatus.MONITOR
        if u < 0.95:
            return UtilizationStatus.HEALTHY
        return UtilizationStatus.NEAR_LIMIT

from collections import defaultdict
from datetime import date, timedelta

@dataclass
class InventoryReport:
    generated_date: date
    licenses: list[LicenseRecord]
    snapshots: dict[str, UtilizationSnapshot]  # tool_id -> latest snapshot
    total_annual_cost_usd: float
    estimated_waste_usd: float
    renewals_within_90_days: list[LicenseRecord]

def build_inventory_report(
    licenses: list[LicenseRecord],
    snapshots: list[UtilizationSnapshot],
    as_of: date,
) -> InventoryReport:
    snap_by_tool = {s.tool_id: s for s in snapshots}
    total_cost = sum(lic.annual_cost_usd for lic in licenses)

    waste = 0.0
    for lic in licenses:
        snap = snap_by_tool.get(lic.tool_id)
        if snap is None or lic.license_type != LicenseType.PER_SEAT_SAAS:
            continue
        u = snap.seat_utilization
        if u is not None and u < 0.50:
            # Waste = cost of unused seats (assume linear cost per seat)
            unused_fraction = 1 - u
            waste += lic.annual_cost_usd * unused_fraction

    renewals_soon = [
        lic for lic in licenses
        if lic.renewal_date <= as_of + timedelta(days=90)
    ]

    return InventoryReport(
        generated_date=as_of,
        licenses=licenses,
        snapshots=snap_by_tool,
        total_annual_cost_usd=total_cost,
        estimated_waste_usd=waste,
        renewals_within_90_days=renewals_soon,
    )
